var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SOLDIER_BORDER_NULL_NULL","text":{"KOREA":"총사대장님! 서쪽에서 더 몰려옵니다!","JPN":"銃士隊長！　西からもっと来ます！","ENG":"Sir! More incoming from the west!","TWN":"隊長！有一群從西邊衝過來！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CURIAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_REAL","text":{"KOREA":"사수들은 탄환을 장전하도록! 내가 시간을 벌겠다!","JPN":"撃ち手は弾丸を装填しろ！　私が時間を稼ぐ！","ENG":"Reload your weapons! I'll buy you some time!","TWN":"狙擊手補充子彈！我來爭取時間！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CURIAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"VILLAGER_BORDER_NULL_WOMAN","text":{"KOREA":"대단해……. 산탄총도 통하지 않던 괴물들을 창 하나로 해치우다니…….","JPN":"すごい……散弾銃も通じなかった化け物を槍一本でやっつけるなんて……","ENG":"Astounding... Even a shotgun couldn't hurt that monster, but he killed it with just a spear...","TWN":"好厲害……連散彈槍都無法對付的怪物，竟然只用一搶就解決掉……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORSE_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"AIDE_BORDER_NULL_NULL","text":{"KOREA":"저희 총사대장님은 노르드나빅을 대표하는 성자들 중에서도 가장 강한 분이시니까요.","JPN":"我々の銃士隊長はノルドナビックを代表する聖者の中でも一番強い方ですから。","ENG":"Our General Musketeer is the strongest of all Helgons in Nordnavik.","TWN":"因爲我們隊長是代表諾爾德萊比的聖者中最強的一個。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORSE_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"VILLAGER_BORDER_NULL_WOMAN","text":{"KOREA":"성자……? 실제로 본 건 처음이네요. 어떤 괴물도 맨손으로 때려눕힐 정도로 힘이 장사라고 들었는데.","JPN":"聖者……？　実際に見るのは初めてです。どんな化け物でも素手で倒せるほど力が強いと聞きましたけど。","ENG":"Helgon...? I've never seen one before. I only heard stories about them being strong enough to take down any monster with nothing but their bare hands...","TWN":"聖人……？這還是我第一次親眼看到，聽說聖者是可以赤手空拳打倒任何怪物的大力士呢。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORSE_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"AIDE_BORDER_NULL_NULL","text":{"KOREA":"하하, 맨손이라니. 그런 얘기는 저도 처음 듣는군요.","JPN":"はは、素手だなんて。そんな話は私も初めて聞きますね。","ENG":"Haha! Bare hands? That's the first time I'm hearing that!","TWN":"哈哈，赤手空拳嗎？這我還是第一次聽說呢。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORSE_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"VILLAGER_BORDER_NULL_WOMAN","text":{"KOREA":"총사대의 성자들은 다들 비밀리에 활동한다고 들었는데, 혹시 저도 보안법으로 끌려가게 되는 걸까요?","JPN":"銃士隊の聖者は秘密裡に活動するものと聞いていますが、私も保安法の違反で引っ張られるのでしょうか？","ENG":"But I thought Helgons in the Musketeer Division were supposed to keep their identities hidden. Will I face legal consequences for knowing this?","TWN":"我聽說射擊隊的聖人都是暗中行動的，難道我有觸犯保安法嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORSE_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"AIDE_BORDER_NULL_NULL","text":{"KOREA":"그런 건 낭설이니 걱정하지 않으셔도 됩니다. 그보다 다친 곳은 없으십니까?","JPN":"それは根も葉もない噂ですので気にしなくて結構です。それより、お怪我はありませんか？","ENG":"You won't have to worry about that. But more importantly, are you hurt?","TWN":"那些都只是不實的謠言，你不用擔心。倒是你有沒有受傷？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORSE_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"VILLAGER_BORDER_NULL_WOMAN","text":{"KOREA":"전 괜찮아요! 그보다 헛간 지하에 마을 아이들이 숨어 있어요!","JPN":"私は大丈夫です！　それより小屋の地下に村の子供たちが隠れているんです！","ENG":"I'm good! Oh, the children are hiding in the barn basement!","TWN":"不用管我！村裡的孩子都在躲在穀倉的地下室！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORSE_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"AIDE_BORDER_NULL_NULL","text":{"KOREA":"걱정 마십시오. 마을은 이미 다른 병사들이 가서 구조를 마친 상황입니다.","JPN":"ご心配なく。村に向かった他の兵士によりすでに救助を終えています。","ENG":"Rest assured. The other soldiers have already finished rescuing the villagers.","TWN":"請放心，其他的士兵已經前往救援。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORSE_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"VILLAGER_BORDER_NULL_WOMAN","text":{"KOREA":"아아……. 정말 감사합니다. 이대로 어떻게 되나 무서웠어요.","JPN":"ああ……本当にありがとうございます。このまま死ぬかと思って怖かったんです。","ENG":"Oh... Thank you so much. I was so scared something might've happened to them...","TWN":"嗚……非常感謝，我剛真的很害怕，不知道這樣下去會發生什麼事。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORSE_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"AIDE_BORDER_NULL_NULL","text":{"KOREA":"아닙니다. 아이들을 지키려고 침식체를 유인하시다니, 만삭의 몸인데도 대단하시군요.","JPN":"いいえ。子供たちを守るために侵食体を誘き出すなんて、身重の体でなかなかできることではありません。","ENG":"No need. But you were brave to try to and save those children from the C.O.s while you were pregnant.","TWN":"沒事的。你都快要臨盆了，竟然為了保護孩子們，而將自己當作侵蝕體的誘餌，真的是好偉大。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORSE_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"VILLAGER_BORDER_NULL_WOMAN","text":{"KOREA":"저 괴물들을 침식체라고 부르는군요…….","JPN":"あの化け物は侵食体というのですね……","ENG":"Those monsters... So \\"C.O.s.” is what you call them...","TWN":"那些怪物叫侵蝕體嗎……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORSE_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"VILLAGER_BORDER_NULL_WOMAN","text":{"KOREA":"그런데 저기……. 수도에 계셔야 할 왕립군 분들이 왜 이런 데 오신 거죠?","JPN":"ところで、あの……首都にいるはずの王立軍がどうしてこんなところに？","ENG":"Oh, and if you don't mind me asking... What is the Royal Army doing out here instead of being in the capital?","TWN":"不過……皇家軍隊不是應該在首都嗎？你們怎麼會來這種地方呢？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORSE_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"AIDE_BORDER_NULL_NULL","text":{"KOREA":"죄송합니다, 부인. 중요한 임무를 수행 중이라는 것 말고는 자세히 말씀드릴 수 없습니다.","JPN":"申し訳ございませんが、奥さん。重要な任務を遂行中であるということ以外には詳しくお話しすることができません。","ENG":"I'm sorry, ma'am. I can't tell you anything more than that we are on a crucial mission.","TWN":"太太，很抱歉，我只能告訴你，我們正在執行重要任務，其餘的無可奉告。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORSE_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"VILLAGER_BORDER_NULL_WOMAN","text":{"KOREA":"방금 그건 뭐죠? 나무들이 흔들렸는데…?","JPN":"今のは何でしょうか？　木々が揺れましたけど……？","ENG":"What was that? I saw the trees shake...!","TWN":"剛剛是怎麼回事？樹都搖搖晃晃的…？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORSE_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"AIDE_BORDER_NULL_NULL","text":{"KOREA":"좋은 징조가 아니라는 건 확실하군요.","JPN":"いい兆しではないのは確かなようですね。","ENG":"That’s definitely not a good omen.","TWN":"確實不是好預兆。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORSE_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"AIDE_BORDER_NULL_NULL","text":{"KOREA":"여길 벗어나야겠습니다. 아이들은 저희가 맡을 테니 말에서 내리지 마십시오.","JPN":"ここから離れましょう。子供たちは我々に任せて、奥さんはそのまま馬上にいてください。","ENG":"We must get out of here. Leave the children to us, and do not get off that horse.","TWN":"必須趕緊離開這裡，孩子們就交給我們，你千萬別下馬。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORSE_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"VILLAGER_BORDER_NULL_WOMAN","text":{"KOREA":"아, 알겠어요! 부탁드려요!","JPN":"わ、わかりました！　お願いします！","ENG":"O-okay! Please help them!","TWN":"好…好！那就拜託了！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"AIDE_BORDER_NULL_NULL","text":{"KOREA":"이런 외지의 마을까지 침식체가 득시글대다니 끔찍하군…….","JPN":"こんなへんぴな村にまで侵食体がうじゃうじゃしているなんて、最悪だ……","ENG":"C.O.s swarming around rural villages? Just horrible...","TWN":"連這種偏僻的村莊也到處都是侵蝕體，真可怕……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"AIDE_BORDER_NULL_NULL","text":{"KOREA":"서둘러 남쪽으로 가지 않으면 돌이킬 수 없겠어.","JPN":"急いで南に向かわなければ、取り返しのつかないことになる。","ENG":"We won't be able to stop this if we don't hurry to the south.","TWN":"必須趕緊往南走，否則情況可能會愈演愈烈。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SOLDIER_BORDER_NULL_NULL","text":{"KOREA":"조심해! 땅이 갈라진다!","JPN":"気をつけろ！　地面が割れる！","ENG":"Watch out! The ground is about to split!","TWN":"小心！地正裂開！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLDIER_BORDER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SOLDIER_BORDER_NULL_NULL","text":{"KOREA":"대형 침식체다! 대열을 유지해!","JPN":"大型の侵食体だ！　隊列を維持しろ！","ENG":"It's a giant C.O.! Maintain formation!","TWN":"是大型侵蝕體！維持隊形！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SOLDIER_BORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"SOLDIER_BORDER_NULL_NULL","text":{"KOREA":"됐어! 통한다!","JPN":"よし！　効いてるぞ！","ENG":"All right! It's working!","TWN":"很好！解決了！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SOLDIER_BORDER_NULL_NULL","text":{"KOREA":"아니야! 상처가 다시 재생하고 있어! 조심해!","JPN":"いいや！　傷が再生している！　気をつけろ！","ENG":"No! Its wounds are already healing! Stay sharp!","TWN":"不！傷口又復原了！小心！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SOLDIER_BORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_REAL","text":{"KOREA":"정면으로 받아내긴 조금 무겁군. 다들 무사한가?","JPN":"正面から受け止めるには少し重たいな。みんな無事か？","ENG":"It's too tough to block it head on even for me. Is everyone all right?","TWN":"正面接招有點辛苦，大家都沒事吧？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SOLDIER_BORDER_NULL_NULL","text":{"KOREA":"네! 덕분에!","JPN":"はい！　銃士隊長のおかげです！","ENG":"Yes, sir! All thanks to you!","TWN":"沒事！謝謝隊長！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLDIER_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SOLDIER_BORDER_NULL_NULL","text":{"KOREA":"총사대장님! 괜찮으십니까?","JPN":"銃士隊長！　大丈夫ですか？","ENG":"Sir! Are you all right?","TWN":"隊長！你還好嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SOLDIER_BORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_REAL","text":{"KOREA":"……이 정도는 문제 없다.","JPN":"……このくらいは問題ない。","ENG":"I'm fine.","TWN":"……這種程度小意思。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_REAL","text":{"KOREA":"다음 사격을 준비해라!","JPN":"次の射撃を準備しろ！","ENG":"Men, get ready to fire!","TWN":"準備下一波射擊！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_REAL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L3_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_REAL","text":{"KOREA":"내가 놈의 갑피를 파괴할 테니 그 부분에 화력을 집중하도록!","JPN":"私がやつの甲皮を破壊するから、その部分に火力を集中させるんだ！","ENG":"I'll destroy its armor, focus fire on that point!","TWN":"我會破壞它的側邊連接處，你們集中火力攻那裡！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SOLDIER_BORDER_NULL_NULL","text":{"KOREA":"지금이다! 쏴!","JPN":"今だ！　撃て！","ENG":"Now! FIRE!!","TWN":"就是現在！開槍！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SOLDIER_BORDER_NULL_NULL","text":{"KOREA":"됐어! 쓰러트렸다!","JPN":"よし！　倒した！","ENG":"We did it! It's down!","TWN":"行了！它倒下了！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLDIER_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SOLDIER_BORDER_NULL_NULL","text":{"KOREA":"하하, 덩치만 컸지 별거 아니잖아!","JPN":"はは、図体が大きいだけで大したことなかったな！","ENG":"Haha! Not so tough now, eh?","TWN":"哈哈，結果只是塊頭大而已，根本沒什麼嘛！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SOLDIER_BORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_REAL","text":{"KOREA":"기뻐하긴 아직 이르다. 주민들을 안전한 곳으로 대피시키기 전까지는 긴장을 늦추지 마라.","JPN":"喜ぶにはまだ早い。住民を安全なところに避難させるまでには気を緩めるな。","ENG":"Don't celebrate yet. It's not over until all the villagers have been evacuated safely.","TWN":"現在還不是高興的時候，在把居民疏散到安全的地方之前，千萬不能鬆懈！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SOLDIER_BORDER_NULL_NULL","text":{"KOREA":"예!","JPN":"はっ！","ENG":"Yes, sir!","TWN":"是！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_REAL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L22_1","type":"narration","speaker":null,"text":{"KOREA":"아아, 벌써 죽여 버린 거야?","JPN":"あーあ、もう殺しちゃったの？","ENG":"Oh no... You killed it already?","TWN":"哎呀～這麼快就被幹掉啦？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"narration","speaker":null,"text":{"KOREA":"여기까지 타고 오느라 살짝 정들 뻔했는데.","JPN":"乗り心地は悪くなかったんだけど。","ENG":"I almost became attached to it as I rode it all the way here.","TWN":"我一路騎著它到這裡來，都有點感情了呢。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_REAL","text":{"KOREA":"넌… 누구지?","JPN":"君は……誰だ？","ENG":"Who... are you?","TWN":"你…是誰？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":null,"text":{"KOREA":"나? 글쎄?","JPN":"あたし？　さあ？","ENG":"Me? Have a guess!","TWN":"我？不好說。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"CYMBALS_NPC_NULL_NONAMED","text":{"KOREA":"너희들 눈에는 내가 뭘로 보여?","JPN":"あんたたちには私が何に見える？","ENG":"Who or what do you think I am?","TWN":"你們看我像什麼？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CYMBALS_NPC_NULL_NONAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"CYMBALS_NPC_NULL_NONAMED","text":{"KOREA":"사람? 아니면 다른 거?","JPN":"人間？　それとも別のもの？","ENG":"Am I a person? Or perhaps something else?","TWN":"像人？還是像什麼？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CYMBALS_NPC_NULL_NONAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SOLDIER_BORDER_NULL_NULL","text":{"KOREA":"멈춰라! 신분을 밝히지 않으면 안전은 보장할 수 없다!","JPN":"止まれ！　正体を明かさない限り、安全は保障できない！","ENG":"Halt! We cannot guarantee your safety if you do not identify yourself!","TWN":"站住！報上你的大名，否則小命不保！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_GUN_RELOAD_SMALL_04"},{"id":"L33_1","type":"dialog","speaker":"CYMBALS_NPC_NULL_NONAMED","text":{"KOREA":"하? 바보 아냐, 너네? 여기까지 힌트를 줬는데도 모르겠어?","JPN":"はあ？　あんたたち、バカじゃないの？　ここまでヒントをあげたのに、わからないわけ？","ENG":"Huh? What a bunch of fools you are. You still can't tell after all those hints?","TWN":"蛤？你們是傻的嗎？提示都已經給到這樣還不知道？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CYMBALS_NPC_NULL_NONAMED","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"CYMBALS_NPC_NULL_NONAMED","text":{"KOREA":"아, 진짜. 너무 멍청해도 골려먹는 재미가 떨어지는데.","JPN":"ああ、もう。バカすぎるとからかい甲斐がなくなるんだけど。","ENG":"Oh, come on. It's no fun when you're THAT stupid.","TWN":"嘖，真是的，有夠笨的，笨到一點都不好玩。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CYMBALS_NPC_NULL_NONAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SOLDIER_BORDER_NULL_NULL","text":{"KOREA":"뭐라고?","JPN":"なんだと？","ENG":"What did you say?!","TWN":"你說什麼？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SOLDIER_BORDER_NULL_NULL","text":{"KOREA":"뭐야? 다들 나만 두고 어디로 간 거야?","JPN":"何だ？　みんな、俺を置いてどこへ行ったんだ？","ENG":"H-huh?! Where'd everyone go?!","TWN":"搞什麼？大家扔下我跑哪裡去了？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_BORDER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SOLDIER_BORDER_NULL_NULL","text":{"KOREA":"……응?","JPN":"……うん？","ENG":"...What?!","TWN":"……嗯？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FIRE_03"},{"id":"L39_1","type":"dialog","speaker":"SOLDIER_BORDER_NULL_NULL","text":{"KOREA":"부, 불이다!! 언제 불이 붙은 거야?!","JPN":"ひ、火だ！！　いつの間に火がついたんだ！？","ENG":"F-FIRE!! I'm trapped in fire!","TWN":"著…著火了！什麼時候著火的？！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SOLDIER_BORDER_NULL_NULL","text":{"KOREA":"누가!! 누가 이것 좀 꺼 줘!! 왜 아무도 없는 거냐고!!","JPN":"誰か！！　誰かこれを消してくれ！！　なんで誰もいないんだよ！！","ENG":"Somebody!! Get me outta here!! Where is everyone?!","TWN":"來人啊！！誰來幫我滅火！！怎麼都沒有人！！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":null,"text":{"KOREA":"아아아악! 뜨거워! 누가 제발 이 불 좀 꺼 줘!","JPN":"ああああ！　熱い！　頼むから誰かこの火を消してくれ！","ENG":"Aaack!!! It's hot! Someone please put it out!","TWN":"啊啊啊啊！好燙！拜託幫我滅火！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L45_1","type":"dialog","speaker":"SOLDIER_BORDER_NULL_NULL","text":{"KOREA":"이봐! 갑자기 왜 그래! 정신 차려! 불이라니 무슨 소리야!","JPN":"おい！　いきなりどうしたんだ！　しっかりしろ！　火なんてついてないぞ！","ENG":"Hey! What's wrong with you?! Snap out of it! There's no fire!","TWN":"喂！你怎麼了？清醒一點！著什麼火？你在胡說什麼！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLDIER_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"SOLDIER_BORDER_NULL_NULL","text":{"KOREA":"위험해! 일단 총부터 빼앗은 다음에…!","JPN":"危ない！　まず銃を奪ってから……！","ENG":"Watch out! Take away his gu–!","TWN":"危險！先把他的槍拿走…！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SOLDIER_BORDER_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L50_1","type":"dialog","speaker":"SOLDIER_BORDER_NULL_NULL","text":{"KOREA":"에드먼드……!","JPN":"エドモンド……！","ENG":"Edmund...!","TWN":"愛德蒙……！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLDIER_BORDER_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"SOLDIER_BORDER_NULL_NULL","text":{"KOREA":"저, 저 녀석…… 왜 자기 입에 총을 넣고 쏜 거야?","JPN":"あ、あいつ……なんで自分の口に銃を突っ込んで撃ったんだ？","ENG":"W-why'd he... put his gun in his mouth and shoot himself?","TWN":"那…那傢伙……爲什麼朝自己的嘴裡開槍？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SOLDIER_BORDER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L4_1","type":"dialog","speaker":"SOLDIER_BORDER_NULL_NULL","text":{"KOREA":"이 개자식! 에드먼드에게 무슨 짓을 한 거냐!","JPN":"このクソ野郎！　エドモンドに何をした！","ENG":"You little...! What did you do to Edmund?!","TWN":"你這個混賬東西！你對愛德蒙做了什麼！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CYMBALS_NPC_NULL_NONAMED","face":"UNIT_SERIOUS2"},"R":null}},"sfx":"FX_COMBAT_ALL_GUN_RELOAD_SMALL_04"},{"id":"L5_1","type":"dialog","speaker":"CYMBALS_NPC_NULL_NONAMED","text":{"KOREA":"아. 아. 아. 안 되지, 이럼 안 돼. 이래서야 한 번에 한 명 꼴이잖아. 효율 최악이라구.","JPN":"あ。あ。あ。ダメだよ、ダメ。これじゃ一度に一人だけじゃない。効率が最悪だって。","ENG":"Ah. Ah. Ah. No. This Won't do. Only one at a time? Such a waste...","TWN":"啊，啊，啊，不行，這可不行，這樣一次才處理一個人，效率不佳。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CYMBALS_NPC_NULL_NONAMED","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CYMBALS_NPC_NULL_NONAMED","text":{"KOREA":"……으흥. 그래. 딱 좋은 방법이 떠올랐어.","JPN":"……うふん。そうね。ぴったりな方法を思いついたわ。","ENG":"Ooh...! I just had a great idea.","TWN":"……嗯哼，就這麼辦吧，我想到一個好方法！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CYMBALS_NPC_NULL_NONAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SOLDIER_BORDER_NULL_NULL","text":{"KOREA":"저 여자가 수상하다! 사정 봐 주지 마!","JPN":"あの女が怪しい！　手加減するな！","ENG":"Something's wrong with that woman! Give her everything you've got!","TWN":"那女人不對勁！別手下留情！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_BORDER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SOLDIER_BORDER_NULL_NULL","text":{"KOREA":"전원 사격 개시!!","JPN":"総員射撃開始！！","ENG":"Men! FIRE!!!","TWN":"全員射擊！！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"AIDE_BORDER_NULL_NULL","text":{"KOREA":"여기까지 왔으면 이제 안전할 겁니다, 부인.","JPN":"ここまで来ればもう安全ですよ、奥さん。","ENG":"You should be safe enough here, ma'am.","TWN":"太太，到這裡應該就安全了。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORSE_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L15_1","type":"dialog","speaker":"AIDE_BORDER_NULL_NULL","text":{"KOREA":"이런 말씀을 드려서 죄송하지만……. 저희는 임무 중이라 계속 모시긴 어렵습니다.","JPN":"申し訳ありませんが……我々は任務中ですので、このままお供することはできません。","ENG":"I'm sorry to say this, but... I can't take you any farther because of our mission.","TWN":"不好意思……因為我們還有要務在身，無法再繼續護送你。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORSE_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"AIDE_BORDER_NULL_NULL","text":{"KOREA":"혹시 이 근처에 의탁할 곳은 있습니까?","JPN":"もしこの辺りに身を寄せられるところはありますか？","ENG":"Is there any place you can stay nearby?","TWN":"這附近有你的棲身之處嗎？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORSE_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"VILLAGER_BORDER_NULL_WOMAN","text":{"KOREA":"강을 건너면 저희 본가가 있는 작은 도시에요. 한동안 신세를 져 보려고요.","JPN":"川を渡ると私の実家がある小さな街があるんです。しばらくはそちらにお世話になろうと思っています。","ENG":"There's a small city where my family live across the river. I'll go there.","TWN":"過江後有個小都市，我的娘家就在那裡，我會暫時先在娘家住一陣子。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORSE_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"AIDE_BORDER_NULL_NULL","text":{"KOREA":"다행입니다. 그럼 여기서 작별하는 게 좋겠군요.","JPN":"安心しました。それではこの辺りで失礼します。","ENG":"That's great to hear. Then I guess this is where we say goodbye.","TWN":"那就好，那就就此告別。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORSE_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"VILLAGER_BORDER_NULL_KIDS","text":{"KOREA":"도와줘서 고맙습니다, 군인 아저씨.","JPN":"助けてくれてありがとう、軍人のおじさん。","ENG":"Thank you for helping us, mister.","TWN":"軍人叔叔，謝謝你來救我們。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VILLAGER_BORDER_NULL_KIDS","face":"UNIT_IDLE"},"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L21_1","type":"dialog","speaker":"VILLAGER_BORDER_NULL_KIDS","text":{"KOREA":"선생님, 왜 집으로 가면 안 돼요?","JPN":"先生、なんで家に帰っちゃダメなの？","ENG":"Why can't we go back home?","TWN":"老師，爲什麼我們不能回家？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"VILLAGER_BORDER_NULL_KIDS","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"VILLAGER_BORDER_NULL_WOMAN","text":{"KOREA":"얘들아, 그러니까 그건……","JPN":"みんな、だからそれは……","ENG":"Children, um... Well the thing is...","TWN":"孩子們，因為……"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"VILLAGER_BORDER_NULL_KIDS","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"AIDE_BORDER_NULL_NULL","text":{"KOREA":"그건 아주 크고 나쁜 해충들이 너희가 살던 집을 갉아먹고 있어서야.","JPN":"それはとても大きくて悪い害虫たちが君たちの住んでいた家をかじってるからだ。","ENG":"There are BIIIG nasty bugs crawling inside your house right now.","TWN":"因為有很大的害蟲在啃食你們的家。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"VILLAGER_BORDER_NULL_KIDS","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"VILLAGER_BORDER_NULL_KIDS","text":{"KOREA":"으엑, 그러면 어떻게 해요?","JPN":"げっ、じゃあどうするの？","ENG":"Eww! Then what do we do?","TWN":"唔，那要怎麼辦？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"VILLAGER_BORDER_NULL_KIDS","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"AIDE_BORDER_NULL_NULL","text":{"KOREA":"그러게 말이야. 그 해충들은 아직 잘 듣는 약도 없거든.","JPN":"そうだな。あの害虫によく効く薬はまだないんだ。","ENG":"I dunno. There aren't any pesticides that work on these critters yet.","TWN":"怎麼辦呢？現在還沒有藥能夠對付那些害蟲。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"VILLAGER_BORDER_NULL_KIDS","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"AIDE_BORDER_NULL_NULL","text":{"KOREA":"지금으로선……","JPN":"今は……","ENG":"So for now...","TWN":"現在……"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"VILLAGER_BORDER_NULL_KIDS","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"VILLAGER_BORDER_NULL_KIDS","text":{"KOREA":"군인 아저씨들이 괴물들을 해치우는 걸 봤어요!","JPN":"軍人のおじさんたちが化け物をやっつけるの見たよ！","ENG":"I saw some soldiers fighting them!","TWN":"我有看到軍人叔叔們打敗那些怪物喔！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VILLAGER_BORDER_NULL_KIDS","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"VILLAGER_BORDER_NULL_KIDS","text":{"KOREA":"맞아! 아저씨들이 그 나쁜 해충들도 잡을 수 있는 거죠?","JPN":"そうだ！　おじさんたちがその悪い虫たちをやっつけるんでしょ？","ENG":"Yeah! You can take out the bugs! Right, mister?","TWN":"有啦！那叔叔們也可以消滅那些害蟲吧？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"VILLAGER_BORDER_NULL_KIDS","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"AIDE_BORDER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"VILLAGER_BORDER_NULL_KIDS","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"AIDE_BORDER_NULL_NULL","text":{"KOREA":"그래. 지금은 어렵지만 언젠가는 잡을 수 있을 거야.","JPN":"そうだね。今は難しいけど、いつかはやっつけるはずだ。","ENG":"Yeah. It'll be difficult, but I will get rid of them all.","TWN":"當然，就算現在沒辦法，但總有一天叔叔們會消滅那些害蟲的。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"VILLAGER_BORDER_NULL_KIDS","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"VILLAGER_BORDER_NULL_WOMAN","text":{"KOREA":"방금 그 총소리……. 마을 쪽에서 들렸어요.","JPN":"今の銃声……村からです。","ENG":"A gunshot...? It's coming from the village.","TWN":"剛才的槍聲……是從村裡傳來的。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"AIDE_BORDER_NULL_NULL","text":{"KOREA":"아직 침식체가 남아 있나 봅니다. 저희가 처리할 테니 걱정마십시오.","JPN":"まだ侵食体が残っているようです。我々が処理しますので、心配なさらないでください。","ENG":"I guess there are still some C.O.s left. We'll take care of them. Don't worry.","TWN":"看來還有侵蝕體，不用擔心，我們會處理的。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"VILLAGER_BORDER_NULL_KIDS","text":{"KOREA":"안녕히 가세요, 군인 아저씨!","JPN":"さよなら、軍人のおじさん！","ENG":"Bye, Mister!","TWN":"軍人叔叔再見～"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORSE_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"VILLAGER_BORDER_NULL_WOMAN","text":{"KOREA":"부디 무사하세요. 기다리는 가족 분들을 생각해서라도.","JPN":"どうかご無事で。待っているご家族のためにも。","ENG":"Stay safe! For your family that’s waiting for you...!","TWN":"請一定要平安歸來，你們的家人們還在等你們呢。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORSE_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"AIDE_BORDER_NULL_NULL","text":{"KOREA":"……감사합니다, 부인.","JPN":"……ありがとうございます、奥さん。","ENG":"Thank you, ma'am.","TWN":"……太太，謝謝你。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORSE_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"AIDE_BORDER_NULL_NULL","text":{"KOREA":"가자, 허밋.","JPN":"行こう、ハーミット。","ENG":"Git, Hermit!","TWN":"走吧，赫米特。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORSE_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SOLDIER_BORDER_NULL_NULL","text":{"KOREA":"초, 총사대장님……. 죄송합니다…….","JPN":"じゅ、銃士隊長……申し訳ありません……","ENG":"My... apologies… sir...","TWN":"隊…隊長……對不起……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_BORDER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SOLDIER_BORDER_NULL_NULL","text":{"KOREA":"저는 분명……. 침식체인 줄 알고…… 쿨럭……!","JPN":"俺は確かに……侵食体だと思って……がはっ……！","ENG":"I was certain... it was a C.O.... *Cough...!*","TWN":"我真的…… 以為是侵蝕體……咳咳……！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_BORDER_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"CYMBALS_NPC_NULL_NONAMED","text":{"KOREA":"아하하하하하! 보고 있어, 셰나?! 따분하다는 건 내가 아니라 너를 두고 하는 소리라고!","JPN":"あははははは！　見てる？　シェナ！　退屈ってのはさ、あたしじゃなくてあんたのこと言ってんのよ！","ENG":"AHAHAHAHA! See that, Shena? I'm not the boring one, you are!!","TWN":"哈哈哈哈！世娜，你看到嗎？！無聊才不是指我，而是對你說的！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CYMBALS_NPC_NULL_NONAMED","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"CYMBALS_NPC_NULL_NONAMED","text":{"KOREA":"이것 봐! 악상에 쓸 만한 소재들이 잔뜩 나왔잖아!","JPN":"これ見てよ！　楽想に使えそうな素材がいっぱい出たじゃない！","ENG":"Just look at this! There's so much material here for composing music!","TWN":"你看！出現這麼多可以用在音樂上的素材！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CYMBALS_NPC_NULL_NONAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"CYMBALS_NPC_NULL_NONAMED","text":{"KOREA":"아. 아. 침착. 침착. 침착해. 침착. 최고단원으로서의 품위가 있지.","JPN":"あ。あ。リラックス。リラックス。落ち着いて。落ち着いて。首席奏者としての品位ってもんがあるの。","ENG":"Ah. Ah. Calm. Yourself. Down. Medius. Act like the Elite Member you are.","TWN":"啊，啊，冷靜，冷靜，冷靜。這樣有失首席樂手的儀態。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CYMBALS_NPC_NULL_NONAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"CYMBALS_NPC_NULL_NONAMED","text":{"KOREA":"후우. 역시 행복하게 살던 것들이라 그런지 반응이 다채롭네.","JPN":"ふう。やっぱり幸せに過ごしていたやつらは反応が豊かだね。","ENG":"Phew... Your reactions are so colorful. Perhaps it's because you lived a happy life?","TWN":"呼～這些傢伙之前應該過得很幸福吧？所以反應特別多采多姿呢。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CYMBALS_NPC_NULL_NONAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"CYMBALS_NPC_NULL_NONAMED","text":{"KOREA":"그래서 저기, 어때? 충성스러운 부하에게 총 맞은 소감은?","JPN":"それで、ねえ、どう？　忠実な部下から銃弾を食らった感想は？","ENG":"So, what's it like getting shot by your subordinate?","TWN":"我說你，感覺如何？忠心的部下對你開槍是什麼感覺？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CYMBALS_NPC_NULL_NONAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_REAL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CYMBALS_NPC_NULL_NONAMED","text":{"KOREA":"그리고 그런 부하를 막으려고 목 졸라 죽인 소감은? 어떤 느낌이야? 응?","JPN":"それから、そんな部下を止めるために首を絞めて殺した感想は？　どんな感じ？　ねえ？","ENG":"Also, what about choking him to death trying to stop him? What's that feel like, hmm?","TWN":"還有，勒死想要對你開槍的部下，又是什麼感覺？嗯？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CYMBALS_NPC_NULL_NONAMED","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CYMBALS_NPC_NULL_NONAMED","text":{"KOREA":"어서 말해!! 그 잘난 아가리 찢어 버리기 전에!!","JPN":"早く言いなさいよ！！　その偉そうな口を八つ裂きにする前に！！","ENG":"Answer me!! Before I rip that pretty mouth of your off your face!!","TWN":"快說！！否則我撕爛你的嘴！！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CYMBALS_NPC_NULL_NONAMED","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L5_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_REAL","text":{"KOREA":"너는…… 대체 뭐 하는 괴물이냐.","JPN":"君は……一体どういう化け物なんだ。","ENG":"What... kind of monster are you?","TWN":"你……到底是什麼怪物！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CYMBALS_NPC_NULL_NONAMED","text":{"KOREA":"하아, 반응이 밋밋하네. 짜증나게.","JPN":"はあ、反応うっす。ウザいね。","ENG":"*Sigh* What a lousy response. So annoying.","TWN":"哀，好無聊的反應，真沒意思。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CYMBALS_NPC_NULL_NONAMED","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_REAL","text":{"KOREA":"목적을 밝혀라.","JPN":"何が目的だ。","ENG":"State your purpose...!","TWN":"說出你的目的吧！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CYMBALS_NPC_NULL_NONAMED","text":{"KOREA":"아. 아. 그렇네. 노느라 까먹고 있었어.","JPN":"あ。あ。そうそう。遊びに夢中で忘れてたわ。","ENG":"Oh. Oh. Right. I totally forgot about that.","TWN":"啊，啊，對吼，光顧著玩差點忘記正事。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CYMBALS_NPC_NULL_NONAMED","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CYMBALS_NPC_NULL_NONAMED","text":{"KOREA":"열쇠라고 하던가? 너희들이 빼돌렸다는 그 특별한 아티팩트? 그걸 가지러 왔어.","JPN":"鍵だっけ？　あんたたちが横取りしたっていう特別なアーティファクト？　それをもらいに来たの。","ENG":"\\"The Key\\", is it? That special artifact you took. I'm here to take it.","TWN":"是叫做鑰匙嗎？你們拿走的那個人造神器？我是來拿那個的。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CYMBALS_NPC_NULL_NONAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_REAL","text":{"KOREA":"역시……. 목적은 그거였나.","JPN":"やはり……目的はそれだったのか。","ENG":"So... That's why you're here...","TWN":"果然……這就是你的目的嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"CYMBALS_NPC_NULL_NONAMED","text":{"KOREA":"웃겨. 그럼 내가 뭐 너네들한테 관심 있어서 여기까지 왔을까 봐?","JPN":"面白いね。じゃあなに、あんたたちに興味があってここまで来たとでも思った？","ENG":"Funny. Did you think I came all the way here for you?","TWN":"笑死人，難不成你以為我是對你們有興趣才來的嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CYMBALS_NPC_NULL_NONAMED","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CYMBALS_NPC_NULL_NONAMED","text":{"KOREA":"그치만 지휘자님이 내가 가져간 아티팩트로 되살아나서 여쭤 보시면 어떡해.","JPN":"だけどさ、マエストロがあたしが持って帰ったアーティファクトで蘇ってからこう聞いたらどうするのよ。","ENG":"But what if I resurrect the Chief Conductor with your Artifact and she asks?","TWN":"萬一指揮家利用我帶回去的人造神器復活後，問我的話怎麼辦？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CYMBALS_NPC_NULL_NONAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CYMBALS_NPC_NULL_NONAMED","text":{"KOREA":"<color=#ffd34c>진귀한 아티팩트를 입수했다고 하던데, 어땠나요?</color>","JPN":"<color=#ffd34c>珍しいアーティファクトを手に入れたと聞きましたが、どうでしたか？</color>","ENG":"<color=#ffd34c>I heard you obtained a rare Artifact. How was it?</color>","TWN":"<color=#ffd34c>我聽說是你將珍貴的人造神器弄到手，這是怎麼回事？</color>"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"CYMBALS_NPC_NULL_NONAMED","face":"UNIT_SERIOUS2"}}}},{"id":"L14_1","type":"dialog","speaker":"CYMBALS_NPC_NULL_NONAMED","text":{"KOREA":"<color=#ffd34c>아. 그냥 다 죽이고 가져왔는데요.</color>","JPN":"<color=#ffd34c>あ。別に、みんな殺して持ってきただけですけど。</color>","ENG":"<color=#ffd34c>Oh, I just massacred everyone and took it.</color>","TWN":"<color=#ffd34c>啊，就我把人都殺掉後拿回來的。</color> "},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CYMBALS_NPC_NULL_NONAMED","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CYMBALS_NPC_NULL_NONAMED","text":{"KOREA":"라고 하면 내가 얼마나 재미없고 따분한 애 취급 받겠어? 안 그래? 응?","JPN":"な～んて言ったらあたしがめちゃくちゃつまんない子に思われるじゃない。そうでしょ？　ね？","ENG":"How boring doesn't that make me sound, hm?","TWN":"我如果這麼回答，那我在她眼裡會是個多麼無聊的人？你說是不是嗎？嗯？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CYMBALS_NPC_NULL_NONAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CYMBALS_NPC_NULL_NONAMED","text":{"KOREA":"저기, 그러니까 나랑 더 재밌는 거 해 볼래?","JPN":"だからさ、あたしともっと楽しいことやってみない？","ENG":"Speaking of which... Wanna do something more fun with me?","TWN":"所以，你想和我來點有趣的事嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CYMBALS_NPC_NULL_NONAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_REAL","text":{"KOREA":"누가……! 네깟 괴물 놈의 농간에 당할 성 싶으냐?!","JPN":"誰が……！　貴様のような化け物の手管にかかるものか！？","ENG":"Do you...! Really think we're going to fall for your tricks?!","TWN":"你以為…！我會被你這個怪物給耍嗎？！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CYMBALS_NPC_NULL_NONAMED","text":{"KOREA":"……헉!","JPN":"……えっ！","ENG":"Kuh...!","TWN":"……唔！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CYMBALS_NPC_NULL_NONAMED","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CYMBALS_NPC_NULL_NONAMED","text":{"KOREA":"지금 그 커다란 창으로 사람을 찌른 거야?","JPN":"今、そのおっきい槍で人を突いたの？","ENG":"Did you just stab a person with that giant spear?","TWN":"你現在是拿那把槍在刺人嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CYMBALS_NPC_NULL_NONAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CYMBALS_NPC_NULL_NONAMED","text":{"KOREA":"어떡해~ 진짜 아프겠다~","JPN":"どうしよう～めっちゃ痛そう～","ENG":"Oh no! That must have weally hwurt...","TWN":"怎麼辦～一定很痛～"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CYMBALS_NPC_NULL_NONAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_REAL","text":{"KOREA":"……뭐라고?","JPN":"……何だと？","ENG":"...What?","TWN":"……什麼？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CYMBALS_NPC_NULL_NONAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"AIDE_BORDER_NULL_NULL","text":{"KOREA":"커헉……!","JPN":"かはっ……！","ENG":"Khhhkk!","TWN":"咳咳……！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"AIDE_BORDER_NULL_NULL","text":{"KOREA":"큐리안…… 총사…… 대장님……","JPN":"キュリアン……銃士……隊長……","ENG":"Sir… General… Musketeer…","TWN":"庫里安……隊……隊長……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_REAL","text":{"KOREA":"데이빗……?","JPN":"デイビッド……？","ENG":"D-David...?","TWN":"大衛……？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"CYMBALS_NPC_NULL_NONAMED","text":{"KOREA":"오우. 목석처럼 굴면서 실은 조금 쌓인 거 아냐? 저런 오빠를 나라고 착각하. 다. 니?","JPN":"わあ。無関心なふりして実はちょっと溜まってたんじゃないの？　あの人をあたしと勘違いす・る・な・ん・て？","ENG":"Wow. Seems like maybe you got a lot of pent-up frustration? I. Can't. Believe. You thought he was me.","TWN":"哇喔，看你一副冷靜的樣子，結果還是有稍微中招的嘛？你是不是把那位哥哥誤認為，是，我，啦？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CYMBALS_NPC_NULL_NONAMED","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"CYMBALS_NPC_NULL_NONAMED","text":{"KOREA":"쿠흡……! 쿠흐흐흐흣!","JPN":"くふっ……！　くふふふふっ！","ENG":"Pff...! PFFFTTT!","TWN":"嘻嘻……！呵呵呵呵！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CYMBALS_NPC_NULL_NONAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_REAL","text":{"KOREA":"……뭐가 그렇게 재미있지?","JPN":"……何がそんなに面白い！","ENG":"What's so amusing to you?","TWN":"……有什麼好笑的？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_REAL","text":{"KOREA":"성유물을 빼앗고 싶다면 맞서 싸워라. 대체 왜 이런 짓까지 하는 거냐.","JPN":"聖遺物を奪いたいのなら正面から来い。どうしてこんなことまでするんだ。","ENG":"If you want the Holy Relic, then fight me. Why are you playing games?","TWN":"想搶走聖遺物的話，有本事就正面對決！到底爲什麼要做這種事？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"CYMBALS_NPC_NULL_NONAMED","text":{"KOREA":"아. 질문 진짜 고리타분하네.","JPN":"あ。ホントつまんない質問だわ。","ENG":"Ugh. You're so old-fashioned.","TWN":"啊，好老套的問題。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CYMBALS_NPC_NULL_NONAMED","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"CYMBALS_NPC_NULL_NONAMED","text":{"KOREA":"음악 좋아하는 사람이 악기 좀 연주하겠다는데 다른 이유가 필요해?","JPN":"音楽好きが楽器を演奏するのに何か理由が必要なわけ？","ENG":"Does a musician need a reason to play her instrument?","TWN":"喜歡音樂的人要演奏一下樂器，哪還需要什麼理由？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CYMBALS_NPC_NULL_NONAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_REAL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"CYMBALS_NPC_NULL_NONAMED","text":{"KOREA":"응? 뭐라고 중얼거리는 거야? 잘 안 들리는데?","JPN":"え？　何ぼそぼそ言ってるの？　聞こえないわよ？","ENG":"Huh? What are you mumbling? I can't hear you.","TWN":"嗯？你在嘀咕？我聽不到？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CYMBALS_NPC_NULL_NONAMED","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_REAL","text":{"KOREA":"…건방 떨지 마라, 이 괴물.","JPN":"……調子に乗るな、この化け物。","ENG":"Don't get cocky with me, you monster...","TWN":"…少囂張，你這怪物！"},"stage":{"bg":"KINGDOM_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_REAL","text":{"KOREA":"너 또한, 무고한 이들에게 위협이 되는 자……!","JPN":"貴様も罪のない人々の脅威となる者……！","ENG":"You are also... A threat to the innocent...!","TWN":"你也是對無辜的人造成威脅的傢伙……！"},"stage":{"bg":"KINGDOM_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_REAL","text":{"KOREA":"내 모든 것을 걸어서라도, 너만은 내가 용서치 않겠다.","JPN":"私の全てをかけてでも、貴様だけは許さない。","ENG":"I will never forgive you, no matter how much I have to lose!","TWN":"就算要付出我的一切，我也絕不會原諒你！"},"stage":{"bg":"KINGDOM_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"CYMBALS_NPC_NULL_NONAMED","text":{"KOREA":"아하하하하하!!","JPN":"アハハハハハハハッ！！","ENG":"Ahahahaha!!","TWN":"哈哈哈哈哈！！"},"stage":{"bg":"KINGDOM_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":"CYMBALS_NPC_NULL_NONAMED","text":{"KOREA":"그래, 화나지?! 화내야지! 처음부터 그랬으면 더 재밌었잖아, 이 빌어 처먹을 인간 놈!!","JPN":"そう、ムカつくでしょ！？　怒ってよ！　最初からそうきたらもっと面白かったのに、このクソ人間野郎が！！","ENG":"You mad?! Of course you are! You should've acted like that from the beginning, you stupid human!","TWN":"是嗎？你生氣啦？！當然要生氣囉！一開始就那樣的話不是更有趣嗎？你這個該死的臭人類！"},"stage":{"bg":"KINGDOM_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"CYMBALS_NPC_NULL_NONAMED","text":{"KOREA":"그 분노로 내 마지막 악장을 멋지게 장식해 줄게!","JPN":"その怒りであたしの最後の楽章をカッコよく飾ってあげる！","ENG":"Your rage will be the climax of my symphony's final movement!","TWN":"我會你的怒氣來裝飾我最後的樂章！"},"stage":{"bg":"KINGDOM_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};